import { useState, useEffect, useContext } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { AuthContext } from '../App';


function EventDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { token } = useContext(AuthContext);

  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [tickets, setTickets] = useState(1);
  const [error, setError] = useState('');
  const [bookingLoading, setBookingLoading] = useState(false);

  useEffect(() => {
    fetchEvent();
  }, [id]);

  const fetchEvent = async () => {
    try {
      const response = await axios.get(`http://localhost:5000/api/events/${id}`);
      setEvent(response.data.event);
    } catch (err) {
      setError('Failed to load event');
    } finally {
      setLoading(false);
    }
  };

  const handleBooking = async () => {
    if (!token) {
      navigate('/login');
      return;
    }

    setBookingLoading(true);
    setError('');

    try {
      const response = await axios.post(
        'http://localhost:5000/api/bookings',
        {
          eventId: id,
          numberOfTickets: tickets
        },
        {
          headers: { Authorization: `Bearer ${token}` }
        }
      );

      alert('Booking created! Redirecting to payment...');
      navigate('/my-bookings');
      
    } catch (err) {
      setError(err.response?.data?.message || 'Booking failed');
    } finally {
      setBookingLoading(false);
    }
  };

  if (loading) {
    return (
      <div>
        <Navbar />
        <div className="container mx-auto px-4 py-20 text-center">
          <div className="text-2xl">Loading event...</div>
        </div>
      </div>
    );
  }

  if (!event) {
    return (
      <div>
        <Navbar />
        <div className="container mx-auto px-4 py-20 text-center">
          <div className="text-2xl text-red-600">Event not found</div>
        </div>
      </div>
    );
  }

  const totalAmount = event.price * tickets;

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar />

      <div className="container mx-auto px-4 py-8">
        <div className="grid md:grid-cols-2 gap-8">
          {/* Event Image */}
          <div>
            <img
              src={event.image || 'https://via.placeholder.com/600x400?text=Event'}
              alt={event.name}
              className="w-full rounded-2xl shadow-2xl"
            />
          </div>

          {/* Event Details */}
          <div>
            <span className="inline-block bg-blue-100 text-blue-600 text-sm font-semibold px-4 py-1 rounded-full mb-4">
              {event.category}
            </span>

            <h1 className="text-4xl font-bold text-gray-800 mb-4">{event.name}</h1>

            <p className="text-gray-700 mb-6 text-lg leading-relaxed">{event.description}</p>

            <div className="space-y-4 mb-8">
              <div className="flex items-center text-lg">
                <span className="mr-3 text-2xl">📅</span>
                <span className="font-medium">
                  {new Date(event.date).toLocaleDateString('en-US', { 
                    weekday: 'long',
                    year: 'numeric', 
                    month: 'long', 
                    day: 'numeric' 
                  })}
                </span>
              </div>

              <div className="flex items-center text-lg">
                <span className="mr-3 text-2xl">⏰</span>
                <span className="font-medium">{event.time}</span>
              </div>

              <div className="flex items-center text-lg">
                <span className="mr-3 text-2xl">📍</span>
                <span className="font-medium">{event.venue}</span>
              </div>

              <div className="flex items-center text-lg">
                <span className="mr-3 text-2xl">🎫</span>
                <span className="font-medium">
                  {event.availableSeats} / {event.totalSeats} seats available
                </span>
              </div>

              <div className="flex items-center text-lg">
                <span className="mr-3 text-2xl">💰</span>
                <span className="text-3xl font-bold text-blue-600">₹{event.price}</span>
                <span className="text-gray-500 ml-2">per ticket</span>
              </div>
            </div>

            {/* Booking Section */}
            <div className="bg-gradient-to-br from-blue-50 to-purple-50 p-6 rounded-2xl shadow-lg">
              <h3 className="text-2xl font-bold mb-4">Book Your Tickets</h3>

              {error && (
                <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded mb-4">
                  {error}
                </div>
              )}

              {/* Number of Tickets */}
              <div className="mb-6">
                <label className="block font-medium mb-2">Number of Tickets</label>
                <div className="flex items-center gap-4">
                  <button
                    onClick={() => setTickets(Math.max(1, tickets - 1))}
                    className="w-12 h-12 bg-white rounded-lg shadow hover:shadow-md transition font-bold text-xl"
                  >
                    -
                  </button>
                  <input
                    type="number"
                    min="1"
                    max={event.availableSeats}
                    value={tickets}
                    onChange={(e) => setTickets(parseInt(e.target.value) || 1)}
                    className="w-20 text-center px-4 py-3 border-2 border-blue-300 rounded-lg font-bold text-xl"
                  />
                  <button
                    onClick={() => setTickets(Math.min(event.availableSeats, tickets + 1))}
                    className="w-12 h-12 bg-white rounded-lg shadow hover:shadow-md transition font-bold text-xl"
                  >
                    +
                  </button>
                </div>
              </div>

              {/* Total Amount */}
              <div className="mb-6 p-4 bg-white rounded-lg">
                <div className="flex justify-between items-center text-xl font-bold">
                  <span>Total Amount:</span>
                  <span className="text-blue-600">₹{totalAmount}</span>
                </div>
              </div>

              {/* Book Button */}
              <button
                onClick={handleBooking}
                disabled={bookingLoading || event.availableSeats === 0}
                className="w-full bg-gradient-to-r from-blue-600 to-purple-600 text-white py-4 rounded-lg font-bold text-lg hover:from-blue-700 hover:to-purple-700 transition disabled:opacity-50 disabled:cursor-not-allowed shadow-lg"
              >
                {bookingLoading ? 'Booking...' : event.availableSeats === 0 ? 'Sold Out' : 'Book Now'}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default EventDetails;
